  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()

  return (
    <div
      data-slot="stepper-separator"
      className={cn(
        "bg-muted-foreground/25 transition-colors data-[state=completed]:bg-primary",
