      data-slot="stepper-separator"
      className={cn(
        "bg-muted-foreground/25 transition-colors data-[state=completed]:bg-primary",
        orientation === "horizontal" ? "h-0.5 flex-1" : "ml-4 w-0.5 flex-1",
        className
      )}
      {...props}
    />
  )
}

function StepperContent({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
}) {
  const { activeStep } = useStepper()

  if (step !== activeStep) {
    return null
  }

  return (
    <div
      data-slot="stepper-content"
      className={cn(className)}
      {...props}
    >
      {children}
    </div>
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}

