"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

type StepperContextProps = {
  activeStep: number
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextProps | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)

  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }

  return context
}

type StepperItemContextProps = {
  step: number
  state: "completed" | "active" | "pending"
}

const StepperItemContext = React.createContext<StepperItemContextProps | null>(
  null
)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)

  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }

  return context
}

function Stepper({
  activeStep,
  orientation = "horizontal",
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  activeStep: number
  orientation?: "horizontal" | "vertical"
}) {
  return (
    <StepperContext.Provider value={{ activeStep, orientation }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "flex gap-4",
          orientation === "horizontal"
            ? "flex-row flex-wrap items-center"
            : "flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

function StepperItem({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
}) {
  const { activeStep } = useStepper()

  const state: "completed" | "active" | "pending" =
    step < activeStep ? "completed" : step === activeStep ? "active" : "pending"

  return (
    <StepperItemContext.Provider value={{ step, state }}>
      <div
        data-slot="stepper-item"
        data-step={step}
        data-state={state}
        className={cn(
          "flex items-center gap-2",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { step, state } = useStepperItem()

  return (
    <button
      data-slot="stepper-trigger"
      className={cn(
        "inline-flex size-8 shrink-0 items-center justify-center rounded-full border text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-[3px] focus-visible:ring-ring/50 disabled:pointer-events-none disabled:opacity-50",
        state === "completed" &&
          "border-primary bg-primary text-primary-foreground",
        state === "active" &&
          "border-primary bg-primary text-primary-foreground",
        state === "pending" &&
          "border-muted-foreground/25 bg-background text-muted-foreground",
        className
      )}
      {...props}
    >
      {children ?? step}
    </button>
  )
}

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn("text-sm font-medium", className)}
      {...props}
    />
  )
}

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-sm text-muted-foreground", className)}
      {...props}
    />
  )
}

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()

  return (
    <div
      data-slot="stepper-separator"
      className={cn(
        "bg-muted-foreground/25 transition-colors data-[state=completed]:bg-primary",
        orientation === "horizontal" ? "h-0.5 flex-1" : "ml-4 w-0.5 flex-1",
        className
      )}
      {...props}
    />
  )
}

function StepperContent({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
}) {
  const { activeStep } = useStepper()

  if (step !== activeStep) {
    return null
  }

  return (
    <div
      data-slot="stepper-content"
      className={cn("basis-full", className)}
      {...props}
    >
      {children}
    </div>
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}
